 1	import React, { FC, useRef } from 'react';
 2	import { Trans } from 'react-i18next';
 3	
 4	import { Button } from '@patternfly/react-core';
 5	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
 6	import { NetworkPolicy } from '@utils/models';
 7	
 8	import NetworkPolicyConditionalSelector from '../NetworkPolicyConditionalSelector';
 9	
10	import NetworkPolicySelectorPreview from './NetworkPolicySelectorPreview/NetworkPolicySelectorPreview';
11	
12	type NetworkPolicyFormPodSelectorProps = {
13	  networkPolicy: NetworkPolicy;
14	  onPolicyChange: (policy: NetworkPolicy) => void;
15	};
16	
17	const NetworkPolicyFormPodSelector: FC<NetworkPolicyFormPodSelectorProps> = ({
18	  networkPolicy,
19	  onPolicyChange,
20	}) => {
21	  const { t } = useNetworkingTranslation();
22	  const podsPreviewPopoverRef = useRef();
23	
24	  const handleMainPodSelectorChange = (updated: string[][]) => {
25	    onPolicyChange({ ...networkPolicy, podSelector: updated });
26	  };
27	
28	  return (
29	    <>
30	      <NetworkPolicyConditionalSelector
31	        dataTest="main-pod-selector"
32	        helpText={t(
33	          'If no pod selector is provided, the policy will apply to all pods in the namespace.',
34	        )}
35	        onChange={handleMainPodSelectorChange}
36	        selectorType="pod"
37	        values={networkPolicy.podSelector}
38	      />
39	      <p>
40	        <Trans t={t}>
41	          Show a preview of the{' '}
42	          <Button
43	            data-test="show-affected-pods"
44	            isInline
45	            ref={podsPreviewPopoverRef}
46	            variant="link"
47	          >
48	            affected pods
49	          </Button>{' '}
50	          that this policy will apply to
51	        </Trans>
52	      </p>
53	      <NetworkPolicySelectorPreview
54	        dataTest="policy-pods-preview"
55	        podSelector={networkPolicy.podSelector}
56	        policyNamespace={networkPolicy.namespace}
57	        popoverRef={podsPreviewPopoverRef}
58	      />
59	    </>
60	  );
61	};
62	
63	export default NetworkPolicyFormPodSelector;

